package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cost;

import java.util.ArrayList;
import java.util.Collection;
import java.util.LinkedHashMap;
import java.util.LinkedHashSet;
import java.util.List;
import java.util.Map;
import java.util.Optional;
import java.util.Set;

import org.eclipse.rdf4j.model.Value;

/**
 * Shared multiset cardinality formulas for tuple algebra planning.
 *
 * Avoid encoding join-order placement rules here. Heuristics that help the current bad query can make a different query
 * worse; this class should estimate the alternatives accurately enough that the search can choose by cost.
 */
public final class EstimateMath {

	private EstimateMath() {
	}

	public static BagEstimate innerJoin(BagEstimate left, BagEstimate right, Set<String> sharedVars) {
		Set<String> joinVars = safeSet(sharedVars);
		double rows = innerJoinRows(left, right, joinVars);
		Map<String, VariableEstimate> variables = joinedVariables(left, right, rows, rows, 0.0d, joinVars, false);
		BagEstimate result = new BagEstimate(rows, left.workRows() + right.workRows() + rows, 0.0d,
				Math.min(left.confidence(), right.confidence()), "inner-join", variables, Map.of(), Map.of());
		return exactJoinedRelation(left, right, joinVars)
				.map(result::withFiniteRelation)
				.orElse(result);
	}

	public static BagEstimate leftJoin(BagEstimate left, BagEstimate right, Set<String> sharedVars) {
		Set<String> joinVars = safeSet(sharedVars);
		double joinRows = innerJoinRows(left, right, joinVars);
		double matchedLeftRows = matchedLeftRows(left, right, joinVars);
		double unmatchedLeftRows = Math.max(0.0d, left.rows() - matchedLeftRows);
		double rows = joinRows + unmatchedLeftRows;
		Map<String, VariableEstimate> variables = joinedVariables(left, right, rows, joinRows, unmatchedLeftRows,
				joinVars, true);
		return new BagEstimate(rows, left.workRows() + right.workRows() + Math.max(left.rows(), rows), 0.0d,
				Math.min(left.confidence(), right.confidence()), "left-join", variables, Map.of(), Map.of());
	}

	public static BagEstimate difference(BagEstimate left, BagEstimate right, Set<String> sharedVars) {
		Set<String> joinVars = safeSet(sharedVars);
		if (joinVars.isEmpty()) {
			return left.withWorkRows(left.workRows() + right.workRows(), "minus-no-shared-vars");
		}
		double matchedLeftRows = matchedLeftRows(left, right, joinVars);
		double rows = Math.max(0.0d, left.rows() - matchedLeftRows);
		Map<String, VariableEstimate> variables = new LinkedHashMap<>();
		for (Map.Entry<String, VariableEstimate> entry : left.variables().entrySet()) {
			variables.put(entry.getKey(), entry.getValue().withBoundRows(rows));
		}
		return new BagEstimate(rows, left.workRows() + right.workRows() + left.rows(), 0.0d,
				Math.min(left.confidence(), right.confidence()), "minus", variables, Map.of(), Map.of());
	}

	public static BagEstimate filter(BagEstimate input, double passRatio, String source) {
		double safeRatio = Double.isFinite(passRatio) ? Math.max(0.0d, Math.min(1.0d, passRatio)) : 1.0d;
		double rows = input.rows() * safeRatio;
		Map<String, VariableEstimate> variables = new LinkedHashMap<>();
		for (Map.Entry<String, VariableEstimate> entry : input.variables().entrySet()) {
			variables.put(entry.getKey(), entry.getValue().scale(safeRatio));
		}
		return new BagEstimate(rows, input.workRows() + input.rows(), input.memoryRows(), input.confidence(), source,
				variables, input.finiteRelations(), input.metrics());
	}

	public static BagEstimate group(BagEstimate input, Set<String> groupVars) {
		Set<String> vars = safeSet(groupVars);
		double rows;
		if (vars.isEmpty()) {
			rows = input.rows() > 0.0d ? 1.0d : 0.0d;
		} else {
			rows = input.relationContaining(vars)
					.map(relation -> relation.distinctRows(vars))
					.orElseGet(() -> vars.stream()
							.map(input::variable)
							.mapToDouble(VariableEstimate::distinctRows)
							.filter(value -> value > 0.0d)
							.min()
							.orElse(Math.min(input.rows(), 1.0d)));
		}
		Map<String, VariableEstimate> variables = new LinkedHashMap<>();
		for (String var : vars) {
			variables.put(var, VariableEstimate.bound(rows, Math.min(rows, input.variable(var).distinctRows())));
		}
		return new BagEstimate(rows, input.workRows() + input.rows(), rows, input.confidence(), "group", variables,
				Map.of(), Map.of());
	}

	public static BagEstimate distinct(BagEstimate input, Set<String> distinctVars) {
		Set<String> vars = safeSet(distinctVars);
		double rows = vars.isEmpty() ? input.rows()
				: input.relationContaining(vars)
						.map(relation -> relation.distinctRows(vars))
						.orElse(Math.min(input.rows(), productDistinct(input, vars)));
		return project(input, vars)
				.withRows(rows, "distinct")
				.withWorkRows(input.workRows() + input.rows(), "distinct-work")
				.withMemoryRows(rows, "distinct-memory");
	}

	public static BagEstimate union(BagEstimate left, BagEstimate right) {
		double rows = left.rows() + right.rows();
		Map<String, VariableEstimate> variables = new LinkedHashMap<>(left.variables());
		for (Map.Entry<String, VariableEstimate> entry : right.variables().entrySet()) {
			variables.merge(entry.getKey(), entry.getValue(), VariableEstimate::plus);
		}
		return new BagEstimate(rows, left.workRows() + right.workRows(), left.memoryRows() + right.memoryRows(),
				Math.min(left.confidence(), right.confidence()), "union", variables, Map.of(), Map.of());
	}

	public static BagEstimate project(BagEstimate input, Set<String> projectedVars) {
		Set<String> vars = safeSet(projectedVars);
		Map<String, VariableEstimate> variables = new LinkedHashMap<>();
		for (String variable : vars) {
			VariableEstimate estimate = input.variable(variable);
			if (estimate.boundRows() > 0.0d || estimate.distinctRows() > 0.0d) {
				variables.put(variable, estimate);
			}
		}
		Map<VariableSetKey, FiniteRelationEstimate> relations = new LinkedHashMap<>();
		for (FiniteRelationEstimate relation : input.finiteRelations().values()) {
			relation.projectTo(vars, "projected-finite-relation")
					.ifPresent(projected -> relations.put(projected.variableSetKey(), projected));
		}
		return new BagEstimate(input.rows(), input.workRows(), input.memoryRows(), input.confidence(), "projection",
				variables, relations, input.metrics());
	}

	public static BagEstimate extendConstant(BagEstimate input, String variable) {
		return input.withVariable(variable, VariableEstimate.bound(input.rows(), input.rows() > 0.0d ? 1.0d : 0.0d));
	}

	public static BagEstimate extendAlias(BagEstimate input, String sourceVariable, String targetVariable) {
		VariableEstimate source = input.variable(sourceVariable);
		if (source.boundRows() <= 0.0d && source.distinctRows() <= 0.0d) {
			return input.withVariable(targetVariable, VariableEstimate.bound(input.rows(), input.rows()));
		}
		return input.withVariable(targetVariable, source.withBoundRows(input.rows()));
	}

	public static BagEstimate slice(BagEstimate input, long offset, long limit) {
		double skipped = Math.max(0L, offset);
		double remaining = Math.max(0.0d, input.rows() - skipped);
		double rows = limit >= 0L ? Math.min(limit, remaining) : remaining;
		double consumed = limit >= 0L ? Math.min(input.rows(), skipped + limit) : input.rows();
		double scale = input.rows() == 0.0d ? 0.0d : rows / input.rows();
		Map<String, VariableEstimate> variables = new LinkedHashMap<>();
		for (Map.Entry<String, VariableEstimate> entry : input.variables().entrySet()) {
			variables.put(entry.getKey(), entry.getValue().scale(scale));
		}
		return new BagEstimate(rows, input.workRows() + consumed, input.memoryRows(), input.confidence(), "slice",
				variables, Map.of(), input.metrics());
	}

	public static BagEstimate order(BagEstimate input) {
		double n = input.rows();
		double sortWork = n * (Math.log(Math.max(2.0d, n)) / Math.log(2.0d));
		return new BagEstimate(input.rows(), input.workRows() + sortWork, n, input.confidence(), "order",
				input.variables(), input.finiteRelations(), input.metrics());
	}

	private static double innerJoinRows(BagEstimate left, BagEstimate right, Set<String> joinVars) {
		if (joinVars.isEmpty()) {
			return left.rows() * right.rows();
		}
		Optional<Map<List<Value>, Double>> leftFrequencies = frequencies(left, joinVars);
		Optional<Map<List<Value>, Double>> rightFrequencies = frequencies(right, joinVars);
		if (leftFrequencies.isPresent() && rightFrequencies.isPresent()) {
			double rows = 0.0d;
			for (Map.Entry<List<Value>, Double> entry : leftFrequencies.get().entrySet()) {
				rows += entry.getValue() * rightFrequencies.get().getOrDefault(entry.getKey(), 0.0d);
			}
			return rows;
		}
		double leftDistinct = tupleDistinct(left, joinVars);
		double rightDistinct = tupleDistinct(right, joinVars);
		return left.rows() * right.rows() / Math.max(1.0d, Math.max(leftDistinct, rightDistinct));
	}

	private static double matchedLeftRows(BagEstimate left, BagEstimate right, Set<String> joinVars) {
		if (joinVars.isEmpty()) {
			return 0.0d;
		}
		Optional<Map<List<Value>, Double>> leftFrequencies = frequencies(left, joinVars);
		Optional<Map<List<Value>, Double>> rightFrequencies = frequencies(right, joinVars);
		if (leftFrequencies.isPresent() && rightFrequencies.isPresent()) {
			return leftFrequencies.get()
					.entrySet()
					.stream()
					.filter(entry -> rightFrequencies.get().containsKey(entry.getKey()))
					.mapToDouble(Map.Entry::getValue)
					.sum();
		}
		double leftDistinct = Math.max(1.0d, tupleDistinct(left, joinVars));
		if (rightFrequencies.isPresent()) {
			double matchRatio = Math.min(1.0d, rightFrequencies.get().size() / leftDistinct);
			return left.rows() * matchRatio;
		}
		double rightDistinct = tupleDistinct(right, joinVars);
		double coveredRightDistinct = estimatedCoveredDistinct(right.rows(), Math.max(leftDistinct, rightDistinct));
		double matchRatio = Math.min(1.0d, Math.min(rightDistinct, coveredRightDistinct) / leftDistinct);
		return left.rows() * matchRatio;
	}

	private static double estimatedCoveredDistinct(double rows, double domainDistinct) {
		if (rows <= 0.0d || domainDistinct <= 0.0d) {
			return 0.0d;
		}
		if (domainDistinct <= 1.0d) {
			return 1.0d;
		}
		double missExponent = rows * Math.log1p(-1.0d / domainDistinct);
		double covered = domainDistinct * -Math.expm1(missExponent);
		return Math.max(0.0d, Math.min(Math.min(rows, domainDistinct), covered));
	}

	private static Map<String, VariableEstimate> joinedVariables(BagEstimate left, BagEstimate right, double rows,
			double rightBoundRows, double rightNullableRows, Set<String> joinVars, boolean leftJoin) {
		Map<String, VariableEstimate> variables = new LinkedHashMap<>();
		Set<String> names = new LinkedHashSet<>();
		names.addAll(left.variables().keySet());
		names.addAll(right.variables().keySet());
		double sharedDistinct = joinVars.isEmpty() ? rows
				: Math.min(tupleDistinct(left, joinVars),
						tupleDistinct(right, joinVars));
		for (String name : names) {
			VariableEstimate leftVar = left.variable(name);
			VariableEstimate rightVar = right.variable(name);
			boolean inLeft = left.variables().containsKey(name);
			boolean inRight = right.variables().containsKey(name);
			if (inLeft && inRight) {
				double distinct = joinVars.contains(name) ? sharedDistinct
						: Math.min(Math.max(leftVar.distinctRows(), rightVar.distinctRows()), rows);
				variables.put(name, VariableEstimate.bound(rows, distinct));
			} else if (inLeft) {
				variables.put(name, VariableEstimate.bound(rows, Math.min(leftVar.distinctRows(), rows)));
			} else if (leftJoin) {
				variables.put(name, new VariableEstimate(Math.min(rightVar.distinctRows(), rightBoundRows),
						rightBoundRows, rightNullableRows, rightVar.sketch()));
			} else {
				variables.put(name, VariableEstimate.bound(rows, Math.min(rightVar.distinctRows(), rows)));
			}
		}
		return variables;
	}

	private static Optional<FiniteRelationEstimate> exactJoinedRelation(BagEstimate left, BagEstimate right,
			Set<String> joinVars) {
		Optional<FiniteRelationEstimate> leftRelation = left.relationContaining(joinVars);
		Optional<FiniteRelationEstimate> rightRelation = right.relationContaining(joinVars);
		if (leftRelation.isEmpty() || rightRelation.isEmpty()) {
			return Optional.empty();
		}
		List<String> outputVars = new ArrayList<>(leftRelation.get().variables());
		for (String variable : rightRelation.get().variables()) {
			if (!outputVars.contains(variable)) {
				outputVars.add(variable);
			}
		}
		Map<List<Value>, Double> rows = new LinkedHashMap<>();
		for (Map.Entry<List<Value>, Double> leftEntry : leftRelation.get().frequencies().entrySet()) {
			for (Map.Entry<List<Value>, Double> rightEntry : rightRelation.get().frequencies().entrySet()) {
				if (!joinKeysMatch(leftRelation.get(), leftEntry.getKey(), rightRelation.get(), rightEntry.getKey(),
						joinVars)) {
					continue;
				}
				List<Value> output = new ArrayList<>(leftEntry.getKey());
				for (int i = 0; i < rightRelation.get().variables().size(); i++) {
					if (!leftRelation.get().variables().contains(rightRelation.get().variables().get(i))) {
						output.add(rightEntry.getKey().get(i));
					}
				}
				rows.merge(FiniteRelationEstimate.tupleKey(output), leftEntry.getValue() * rightEntry.getValue(),
						Double::sum);
			}
		}
		return Optional.of(FiniteRelationEstimate.fromFrequencies(outputVars, rows, "joined-finite-relation"));
	}

	private static boolean joinKeysMatch(FiniteRelationEstimate left, List<Value> leftTuple,
			FiniteRelationEstimate right, List<Value> rightTuple, Set<String> joinVars) {
		for (String variable : joinVars) {
			Value leftValue = leftTuple.get(left.variables().indexOf(variable));
			Value rightValue = rightTuple.get(right.variables().indexOf(variable));
			if (!FiniteRelationEstimate.sameValue(leftValue, rightValue)) {
				return false;
			}
		}
		return true;
	}

	private static Optional<Map<List<Value>, Double>> frequencies(BagEstimate estimate, Set<String> vars) {
		return estimate.relationContaining(vars)
				.map(relation -> relation.frequencyBy(vars));
	}

	private static double tupleDistinct(BagEstimate estimate, Set<String> vars) {
		return estimate.relationContaining(vars)
				.map(relation -> relation.distinctRows(vars))
				.orElseGet(() -> productDistinct(estimate, vars));
	}

	private static double productDistinct(BagEstimate estimate, Collection<String> vars) {
		double product = 1.0d;
		boolean hasAny = false;
		for (String var : vars) {
			double distinct = estimate.variable(var).distinctRows();
			if (distinct > 0.0d) {
				product *= distinct;
				hasAny = true;
			}
		}
		return hasAny ? Math.min(product, Math.max(1.0d, estimate.rows())) : Math.max(1.0d, estimate.rows());
	}

	private static Set<String> safeSet(Set<String> vars) {
		return vars == null || vars.isEmpty() ? Set.of() : Set.copyOf(vars);
	}
}
